class Solution:
    def hasSameDigits(self, s):
        # independent re-derivation: direct simulation of the folding process.
        # correct but only intended for short strings -- the real solution must
        # avoid this for the full length range.
        digits = [int(c) for c in s]
        while len(digits) > 2:
            digits = [(a + b) % 10 for a, b in zip(digits, digits[1:])]
        return digits[0] == digits[1]

