class Solution:
    def hasSameDigits(self, s):
        FACT5 = [1, 1, 2, 1, 4]
        def small_comb5(n, k):
            if k < 0 or k > n:
                return 0
            return FACT5[n] * pow(FACT5[k], 3, 5) % 5 * pow(FACT5[n - k], 3, 5) % 5
        def comb_mod5(n, k):
            if k < 0 or k > n:
                return 0
            res = 1
            while n > 0 or k > 0:
                ni, ki = n % 5, k % 5
                if ki > ni:
                    return 0
                res = res * small_comb5(ni, ki) % 5
                n //= 5
                k //= 5
            return res
        def comb_mod2(n, k):
            if k < 0 or k > n:
                return 0
            return 1 if (n & k) == k else 0
        def comb_mod10(n, k):
            a = comb_mod2(n, k)
            b = comb_mod5(n, k)
            for x in range(10):
                if x % 2 == a and x % 5 == b:
                    return x
            raise ValueError('no crt solution')
        n = len(s)
        m = n - 2
        digits = [int(c) for c in s]
        coeffs = [comb_mod10(m, j) for j in range(m + 1)]
        d0 = sum(coeffs[j] * digits[j] for j in range(m + 1)) % 10
        d1 = sum(coeffs[j] * digits[j + 1] for j in range(m + 1)) % 10
        return d0 == d1

