var hasSameDigits = function(s) {
    const FACT5 = [1, 1, 2, 1, 4];
    function powmod(a, e, mod) {
        a = a % mod;
        let r = 1;
        while (e > 0) {
            if (e & 1) r = (r * a) % mod;
            a = (a * a) % mod;
            e = Math.floor(e / 2);
        }
        return r;
    }
    function smallComb5(n, k) {
        if (k < 0 || k > n) return 0;
        return (FACT5[n] * powmod(FACT5[k], 3, 5) % 5 * powmod(FACT5[n - k], 3, 5)) % 5;
    }
    function comb5(n, k) {
        if (k < 0 || k > n) return 0;
        let res = 1;
        while (n > 0 || k > 0) {
            const ni = n % 5, ki = k % 5;
            if (ki > ni) return 0;
            res = (res * smallComb5(ni, ki)) % 5;
            n = Math.floor(n / 5);
            k = Math.floor(k / 5);
        }
        return res;
    }
    function comb2(n, k) {
        if (k < 0 || k > n) return 0;
        return (n & k) === k ? 1 : 0;
    }
    function comb10(n, k) {
        const a = comb2(n, k), b = comb5(n, k);
        for (let x = 0; x < 10; x++) {
            if (x % 2 === a && x % 5 === b) return x;
        }
        throw new Error('no crt solution');
    }
    const n = s.length;
    const m = n - 2;
    const digits = s.split('').map(Number);
    const C = new Array(m + 1);
    for (let j = 0; j <= m; j++) C[j] = comb10(m, j);
    let d0 = 0, d1 = 0;
    for (let j = 0; j <= m; j++) {
        d0 = (d0 + C[j] * digits[j]) % 10;
        d1 = (d1 + C[j] * digits[j + 1]) % 10;
    }
    return d0 === d1;
};
